import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"32. Accident Pay","description":"","frontmatter":{"title":"32. Accident Pay","eba":"Allied Health Professionals 2021-2026","topics":["wages","accident-pay"]},"headers":[],"relativePath":"ebas/allied-health/wages/32-accident-pay.md","filePath":"ebas/allied-health/wages/32-accident-pay.md"}'),i={name:"ebas/allied-health/wages/32-accident-pay.md"};function r(s,e,c,p,l,y){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_32-accident-pay" tabindex="-1">32. Accident Pay <a class="header-anchor" href="#_32-accident-pay" aria-label="Permalink to &quot;32. Accident Pay&quot;">​</a></h1><p><strong>32.1</strong> Subject to this clause 32, where an Employee is receiving a weekly payment of compensation in respect of an incapacity under the WIRC Act, the Employee will receive accident make up pay equal to the ordinary time earnings they would ordinarily receive, less the amount of weekly compensation.</p><p><strong>32.2</strong> Accident make up pay will only be payable to an eligible Employee whilst that Employee remains in the employment of the Employer.</p><p><strong>32.3</strong> An Employer is not liable to pay accident make up pay:</p><p><strong>(a)</strong> in relation to an incapacity which occurred during the first two (2) weeks of the employment unless such incapacity continues beyond the first two (2) weeks of employment in which case the maximum period of payment of accident make up pay will apply only to the period of incapacity after the first two (2) weeks;</p><p><strong>(b)</strong> in relation to any injury, during the first five (5) normal working days of incapacity. However, an Employee who contracts an infectious disease in the course of duty is entitled to receive workers’ compensation therefore will receive accident pay from the first day of incapacity;</p><p><strong>(c)</strong> for any period that weekly payments under the WIRC Act cease;</p><p><strong>(d)</strong> whilst the Employee is on any other paid leave provided for in this Agreement;</p><p><strong>(e)</strong> unless the Employee has given notice in writing to the Employer of an injury as soon as practicable after the occurrence of the injury;</p><p><strong>(f)</strong> upon the death of the Employee.</p><p><strong>32.4</strong> The maximum period or aggregate periods of accident make up pay for which the Employer is liable under this clause 32 is 39 weeks for any one injury.</p>',11)])])}const m=t(i,[["render",r]]);export{h as __pageData,m as default};
